$ErrorActionPreference = 'Stop'
[Console]::OutputEncoding = [System.Text.Encoding]::UTF8

$src = 'D:\Codex\_protocol_working_copy.docx'
$dst = 'D:\Codex\2026年度江西省结核病重点实验科研课题申请书_保留原格式_Protocol审查修订版_2026-03-25_v3.docx'
Copy-Item -LiteralPath $src -Destination $dst -Force

$word = New-Object -ComObject Word.Application
$word.Visible = $false
$doc = $word.Documents.Open($dst)

function Replace-AllText {
    param(
        [string]$FindText,
        [string]$ReplaceText
    )

    $range = $doc.Content
    $find = $range.Find
    $find.ClearFormatting()
    $find.Replacement.ClearFormatting()
    $find.Text = $FindText
    $find.Replacement.Text = $ReplaceText
    $wdReplaceAll = 2
    $wdFindContinue = 1
    [void]$find.Execute($FindText, $false, $false, $false, $false, $false, $true, $wdFindContinue, $false, $ReplaceText, $wdReplaceAll)
}

$pairs = @(
    @{ old = '课　题　名　称IL-6联合hs-CRP动态监测在血液透析合并肺结核患者中的预后预测研究'; new = '课　题　名　称IL-6联合hs-CRP动态监测在血液透析合并肺结核患者炎症负荷评估及预后预测研究' },
    @{ old = '应用研究型'; new = '应用研究型（前瞻性观察性探索研究）' },
    @{ old = '结核病  血液透析，IL-6,hs-CRP,'; new = '结核病；血液透析；IL-6；hs-CRP；动态监测；预后预测' },
    @{ old = '主持课题设计实施'; new = '主持课题设计、临床统筹与质量控制' },
    @{ old = '资料收集数据分析'; new = '病例入组、资料收集与数据整理' },
    @{ old = '临床资料收集和诊断'; new = '临床资料收集、肺结核诊断与结局核查' },
    @{ old = '研究对象筛选'; new = '研究对象筛选与治疗过程管理' },
    @{ old = '样本处理和检测'; new = '样本处理、IL-6/hs-CRP检测与质控' },
    @{ old = '负责人黄华，主任医师，从事传染病工作20余年，在省、国家级杂志发表论文20余篇，承担的各类课题5项。课题负责人从事临床工作20余年，主持省级科研项目 5项，发表相关论文20余 篇；核心成员包括临床医师4名（主任医师1名、主治医师3名）、检验技师2名（均为副主任技师）均从事结核病重点实验室检测工作10年以上，具备丰富的临床实践、实验室操作和数据分析经验。课题组有传染病学正高职称2名，负责人从事结核病临床治疗20余年，任中华医学会结核病学分会委员，中国医促会结核病防治分会委员，省结核病专业委员会副主任委员，市结核病专业委员会主任委员。负责人及成员负责或参与省市级多项课题，有一定的科研素质及能力。'; new = '负责人黄华，主任医师，从事传染病及结核病临床工作20余年，主持省级科研项目5项，发表相关论文20余篇，具备较好的课题组织与实施经验。课题组由结核病临床医师和医学检验人员组成，能够完成病例筛选、样本采集、实验室检测、随访和数据整理等工作，具备开展本课题的专业基础。' },
    @{ old = '医院是以传染病（包括结核病）和肿瘤两大专科特色而建立的一所专科三级甲等医院，拥有病床930张，结核病 区118张。病床使用率均超过110%，是市结核病诊疗中心。病源覆盖全市及周边湖北、安徽等县市。我院结核科 在省学术界均具有一定社会影响，有能力支撑本课题的实施与完成。'; new = '九江市第三人民医院为传染病专科三级甲等医院，是当地结核病诊疗中心，具备较稳定的结核病病例来源和血液透析相关诊疗基础，拥有化学发光仪、血球分析仪、高速离心机及胸部CT等必要设备，可为本研究提供临床病例、实验检测、伦理申报和数据管理支持。课题聚焦维持性血液透析合并活动性肺结核这一高风险特殊共病人群，具有明确临床意义和应用价值，实施方案总体可行。' },
    @{ old = '4.1.1.维持性血液透析（MHD）患者是结核病（TB）的极高危人群。我国MHD人群庞大，其结核病发病率显著高于普通人群，但由于这类患者临床表现常不典型，且存在固有的“微炎症状态”，表现为C反应蛋白（CRP）和白介素-6（IL-6）的基础水平升高[1] 导致结核病的早期识别和炎症负荷评估极为困难 [2, 3]。MHD患者本身存在的肌少症、营养不良等合并症，进一步加剧了其免疫功能的紊乱，使得共病状态下的病情演变更为复杂 [4, 5]。'; new = '4.1.1 维持性血液透析（MHD）患者属于结核病高风险人群，该类患者长期处于免疫功能紊乱、营养不良及慢性微炎症状态。一旦合并活动性肺结核，临床表现往往不典型，且透析基础炎症与结核活动相关炎症相互叠加，使病情识别、炎症负荷评估及疗效判断均更加困难。' },
    @{ old = '4.1.2因此，如何精准评估MHD合并肺结核患者的炎症负荷，并有效预测其治疗转归，是当前临床亟待解决的关键问题。白细胞介素-6（IL-6）作为炎症反应的核心启动因子，与超敏C反应蛋白（hs-CRP）联合检测，能够更全面地反映从免疫激活到急性时相反应的炎症级联过程。近期的荟萃分析已证实，IL-6是CKD患者不良结局（包括心血管事件和全因死亡）的强预测因子 [6]，而另一项系统综述也明确了其与CRP在CKD进展中的核心地位 [5]。'; new = '4.1.2 当前临床实践中，缺乏针对MHD合并肺结核患者的简便、可重复、可动态追踪的炎症评估工具。IL-6是炎症反应上游关键细胞因子，hs-CRP反映急性时相反应水平，二者联合检测有望更完整地反映该特殊人群的炎症级联变化，为治疗过程中的风险分层和预后提示提供依据。' },
    @{ old = '4.1.3本研究聚焦于“IL-6联合hs-CRP动态监测”这一策略，旨在为临床提供一套能有效区分“结核活动性炎症”与“透析基础炎症”的评估工具，通过动态观察其变化轨迹，早期预警治疗失败风险，指导个体化治疗方案的调整，对改善这一特殊共病人群的预后具有重大的临床意义和广阔的应用前景。'; new = '4.1.3 本研究拟通过前瞻性动态监测IL-6与hs-CRP，探索其在区分透析基础微炎症与结核相关炎症负荷、提示治疗反应和不良结局风险中的应用价值，为后续扩大样本验证研究和临床精细化管理提供初步依据。' },
    @{ old = '4.2.1 血液透析患者的微炎症状态与结核共病风险'; new = '4.2.1 血液透析患者普遍存在微炎症状态，透析过程本身亦会影响炎症因子水平。近年来，国内研究和专家共识已逐步关注成人血液透析患者结核感染风险管理，但现有工作仍主要集中于筛查和诊断，对动态炎症监测与治疗过程风险分层的证据相对不足。' },
    @{ old = '目前，国内外研究已明确MHD患者普遍存在微炎症状态，透析过程本身即可诱发炎症因子水平的动态变化 [7]。针对这一人群，国内研究开始关注其合并结核感染的特殊性。顾海霞等 [8] 的研究深入分析了MHD合并初治结核患者的临床特点，指出其预后较差，提示需要更精准的风险分层工具。沈鑫等 [2] 最新发布的专家共识也系统阐述了成人血液透析患者结核感染的风险管理策略，强调了早期识别和规范管理的重要性，但目前的管理重点多聚焦于筛查环节。'; new = '4.2.2 在透析及慢性肾病领域，IL-6和CRP与不良结局之间的关联已获得较多研究支持；在活动性肺结核领域，炎症指标对疾病活动度评估亦具有潜在价值。然而，针对“维持性血液透析合并活动性肺结核”这一特殊共病场景，仍缺乏以前瞻性动态监测为核心的系统研究。' },
    @{ old = '4.2.2 炎症标志物IL-6与hs-CRP的预后价值'; new = '4.2.3 当前相关研究的发展趋势，正从单次测量走向动态轨迹评估，从单指标判断走向联合指标分析，从一般人群外推走向高风险特殊人群精准分层。本课题顺应这一趋势，具有一定的新意和现实需求。' },
    @{ old = '4.3.1聚焦特殊共病人群：针对“血液透析+活动性肺结核”这一临床处理棘手、炎症背景复杂的人群，深入探索“MHD+TB”这一免疫受损与感染叠加的特殊人群的炎症特征,填补该领域临床数据空白。'; new = '4.3.1 聚焦特殊共病人群：针对“维持性血液透析+活动性肺结核”这一临床处理复杂、炎症背景混杂、预后较差的人群开展研究，具有较强的问题导向。' },
    @{ old = '4.3.2 引入动态联合监测：区别于传统的单次、单指标检测，本研究设计在抗结核治疗前（0周）、治疗强化期末（8周）、以及治疗结束时（24周）进行多点联合检测，关注炎症指标的纵向变化轨迹而非孤立的基线值。'; new = '4.3.2 引入动态联合监测：不同于单次、单指标检测，本研究将在基线、治疗强化期结束时及治疗阶段性完成时进行联合检测，重点观察IL-6与hs-CRP的变化轨迹。' },
    @{ old = '5.1.1. 研究对象与分组：设置A组：血液透析合并肺结核组，B组：单纯血液透析组，C组：单纯肺结核组，比较血液透析合并肺结核组（A组）、单纯血液透析组（B组）、单纯肺结核组（C组）在基线时的IL-6及hs-CRP水平，明确“共病”状态下的炎症负荷特征。'; new = '5.1.1 研究对象与分组：设置A组为维持性血液透析合并活动性肺结核组，B组为单纯维持性血液透析组，C组为单纯活动性肺结核组。首先比较三组基线IL-6及hs-CRP水平，识别共病状态下的炎症负荷特征。' },
    @{ old = '5.1.2. 动态监测内容：对A、C组患者，在抗结核治疗的第0个月、2个月、6个月同步检测IL-6和hs-CRP,在B组患者，在第0个月、6个月同步检测IL-6和hs-CRP。'; new = '5.1.2 动态监测内容：对A组和C组分别在基线、治疗强化期结束时和治疗阶段性完成时检测IL-6和hs-CRP；对B组在基线及随访阶段检测上述指标，用于观察透析背景炎症水平变化。正式实施时统一采样时间窗，并尽量固定检测流程。' },
    @{ old = '5.1.3. 预后预测研究：随访A组患者1年，记录全因死亡、心血管事件、结核复发等终点事件。通过ROC曲线分析基线及治疗2个月后的IL-6/hs-CRP水平对不良预后的预测价值。'; new = '5.1.3 预后探索内容：前瞻性随访A组患者，记录死亡、治疗失败、严重不良反应导致方案中断或调整、结核复发等不良结局，探索基线指标及其动态变化与预后的关联。' },
    @{ old = '5.2.1. 排除干扰因素：需严格记录透析前后采血时间（统一在透析前采血），排除透析过程中急性炎症反应对结果的干扰。'; new = '5.2.1 排除干扰因素：统一在透析前采血，记录采血时点、临床状态及合并事件，尽量减少透析过程、急性炎症及操作差异对结果的影响。' },
    @{ old = '5.2.2. 标准化动态监测：确保同一患者不同时间点的检测在同一批次或相同质控标准下进行，保证数据的纵向可比性。'; new = '5.2.2 标准化动态监测：统一样本采集、处理、保存、检测及质控流程，保证不同时间点结果具有纵向可比性。' },
    @{ old = '5.3.1. 学术成果：发表论文1篇，阐述IL-6联合hs-CRP动态监测在预测血液透析合并肺结核患者预后中的作用。'; new = '5.3.1 形成血液透析合并肺结核患者IL-6与hs-CRP动态监测数据库和研究报告，阐明其在炎症负荷评估及不良结局风险提示中的初步价值。' },
    @{ old = '5.3.2. 数据报告：提交患者完整检测数据及分析结果的研究报告1份。'; new = '5.3.2 发表相关论文1篇，并为后续扩大样本验证研究提供设计依据。' },
    @{ old = '6.1.1. 研究对象选择：选取2026年4月-2027年6月在九江市第三人民医院血透室及结核科就诊的患者。'; new = '6.1.1 研究对象选择：选取2026年4月至2027年6月在九江市第三人民医院血透室及结核科就诊、符合纳入标准且签署知情同意书的患者。' },
    @{ old = 'A组：维持性血液透析（每周2-3次）≥3个月；符合活动性肺结核诊断标准（微生物学确诊或临床诊断+治疗决策）。'; new = 'A组：年龄18-80岁；维持性血液透析至少3个月；符合活动性肺结核诊断标准（微生物学确诊或临床诊断并已启动抗结核治疗）；能够接受随访。' },
    @{ old = 'B组：维持性血液透析≥3个月；无活动性结核证据；与A组年龄、性别、透析龄匹配。'; new = 'B组：年龄18-80岁；维持性血液透析至少3个月；无活动性结核证据；与A组在年龄、性别及透析龄方面尽量保持可比。' },
    @{ old = 'C组：新诊断活动性肺结核；eGFR≥90 ml/min；与A组年龄、性别匹配。'; new = 'C组：年龄18-80岁；新诊断活动性肺结核；无维持性血液透析治疗史；与A组在年龄、性别方面尽量保持可比。' },
    @{ old = '三组年龄18-80岁，签署知情同意书'; new = '三组患者均需签署知情同意书。活动性肺结核最终诊断流程和匹配策略在正式实施前由课题组进一步统一。[需PI确认]' },
    @{ old = '排除标准：1、其他活动性感染（如HIV、乙肝活动期、严重细菌感染）；2、自身免疫性疾病（SLE、RA等）或正在使用免疫抑制剂；3、恶性肿瘤活动期4、近1个月内有手术、创伤、急性心血管事件；5、拒绝参与或无法随访'; new = '排除标准：合并其他明确活动性感染、自身免疫性疾病活动期或免疫抑制治疗、活动期恶性肿瘤、近1个月重大手术或急性心脑血管事件，以及研究者判断无法完成随访者。' },
    @{ old = '6.1.3. 检测方法：'; new = '6.1.3 检测方法：采用化学发光法检测血清IL-6水平，采用免疫比浊法检测hs-CRP，同时记录血常规、白蛋白及必要的结核病相关临床资料。' },
    @{ old = '采用化学发光法检测血清IL-6水平；采用免疫比浊法检测hs-CRP。同时记录血常规、白蛋白。'; new = '样本采集原则上统一在透析前进行，并记录采样日期、距离上次透析时间、是否存在发热或其他急性事件。非透析患者尽量在固定时间段采样，以减少检测波动。' },
    @{ old = '设置三组：共病组（MHD+TB）：60例，单纯MHD组：60例， 单纯TB组：60例'; new = '本研究拟纳入共病组（MHD+TB）60例、单纯MHD组60例、单纯TB组60例。鉴于目前尚未形成完整样本量计算依据，本课题定位为探索性研究，上述例数主要用于可行性评估和初步关联分析。[需统计师确认]' },
    @{ old = '质量控制参照中国防痨协会组织编写《结核病实验室检测技术标准化操作示意图集》及质量保证手册。'; new = '质量控制参照结核病实验室相关技术标准和本院检验质控要求执行，并建立病例报告表、关键变量核对、实验室批次记录和结局事件核实流程。' },
    @{ old = '6.1.6. 统计学分析：采用SPSS26.0软件，重复测量方差分析动态变化；Logistic回归分析影响预后的独立因素；Kaplan-Meier生存曲线分析不同炎症水平组的生存差异。'; new = '6.1.6 统计学分析：采用SPSS 26.0或其他适宜软件进行分析。三组基线比较根据资料类型选择合适统计方法；纵向数据可采用重复测量分析或混合效应模型；A组预后探索可采用Logistic回归、Cox回归及ROC曲线等方法。所有结果以探索性解释为主。[需统计师确认]' },
    @{ old = '6.2.1 筛选入组：严格按纳排标准筛选MHD+TB患者。'; new = '6.2.1 筛选入组：严格按纳入和排除标准筛选研究对象，完成知情同意。' },
    @{ old = '6.2.2.基线数据采集：入组时（T0）采集血样测IL-6/hs-CRP，记录临床资料。'; new = '6.2.2 基线数据采集：入组时采集血样检测IL-6和hs-CRP，并记录人口学资料、透析相关资料、结核病诊断资料及基础实验室指标。' },
    @{ old = '6.2.3.干预与随访：统一按指南进行抗结核治疗，常规透析。'; new = '6.2.3 临床管理与随访：A组和C组按临床规范接受抗结核治疗，A组同时接受常规透析治疗；研究不额外改变标准诊疗路径。' },
    @{ old = '6.2.4. 动态监测：T8周（强化期末）、T24周（疗程结束）再次检测IL-6/hs-CRP。'; new = '6.2.4 动态监测：在基线、治疗强化期结束时和治疗阶段性完成时再次检测IL-6和hs-CRP，统一允许窗口期和采样流程。[需PI确认]' },
    @{ old = '6.2.5. 终点判断：记录痰菌阴转时间、肺部CT吸收情况、是否死亡、是否因严重不良反应停药。'; new = '6.2.5 终点判断：重点记录A组患者的全因死亡、治疗失败、严重不良反应导致方案中断或调整、结核复发等不良结局，并同步记录痰菌阴转、影像吸收等过程性指标。主要复合终点构成由课题组最终确认。[需PI确认]' },
    @{ old = '6. 2.6 统计分析：绘制IL-6/hs-CRP随时间变化的曲线，分析其与预后的关联性。'; new = '6.2.6 统计分析：绘制IL-6和hs-CRP随时间变化曲线，分析其与临床结局之间的关系，并比较单一指标与联合指标的风险提示能力。' },
    @{ old = '7.1.2026年4月-2026年6月：伦理审查，预实验优化检测流程：'; new = '7.1.2026年4月-2026年6月：完成伦理申报、研究人员培训、病例报告表设计及检测流程优化。' },
    @{ old = '7.2.2026年7月-2027年3月：病例入组高峰期，完成所有入组患者的基线及随访点样本采集与检测。考核指标：完成30例共病组患者的入组及2个月随访。'; new = '7.2.2026年7月-2027年3月：开展病例入组和基线检测，完成阶段性随访及样本采集。考核指标：完成共病组阶段性入组及8周随访。' },
    @{ old = '7.3.2027年4月-2027年9月：完成剩余病例的随访，整理数据库，进行统计学分析。考核指标：完成所有实验室检测和数据录入。'; new = '7.3.2027年4月-2027年9月：完成剩余病例随访、数据库整理和统计分析。考核指标：完成全部实验室检测、数据录入和关键结局核查。' },
    @{ old = '7.4.2027年10月-2027年12月：撰写论文，准备结题报告。考核指标：投稿论文1篇，提交结题报告。'; new = '7.4.2027年10月-2027年12月：完成研究总结、论文撰写和结题材料提交。考核指标：投稿论文1篇，提交结题报告。' },
    @{ old = '8.1明确IL-6联合hs-CRP动态监测在血液透析合并肺结核患者中的应用价值，特别是治疗2个月后IL-6下降幅度<30%作为预测治疗失败或死亡风险的预警指标；'; new = '8.1明确维持性血液透析合并活动性肺结核患者的炎症负荷特征及IL-6联合hs-CRP的动态变化规律；' },
    @{ old = '8.2建立该特殊人群的“炎症负荷”临床评估流程。'; new = '8.2探索IL-6联合hs-CRP动态监测在提示治疗反应和不良结局风险中的应用价值，并为后续验证研究提供初步依据；' },
    @{ old = '8.3.发表论文1篇。'; new = '8.3发表论文1篇，形成该特殊人群炎症评估的初步研究基础。' },
    @{ old = '提高对高危共病人群的管理水平，通过早期预警炎症风暴，降低死亡率，为“健康中国2030”中特殊人群结核病防治提供九江经验。'; new = '提高对维持性血液透析合并肺结核这一高风险特殊人群的识别、评估和随访管理水平，为区域结核病防治和慢病合并感染管理提供本地临床证据。' },
    @{ old = 'IL-6和hs-CRP为常规检测项目，费用低，易于推广。通过精准评估，避免不必要的二线抗结核药物使用及延长住院时间，节约医疗资源。医院通过开展特色监测项目，提升医院在肾内科合并感染领域的诊疗声誉，吸引周边地区疑难病例。'; new = 'IL-6和hs-CRP具有一定临床可及性。若动态监测能够帮助更早识别高风险患者、优化随访和治疗管理，则有望减少部分无效诊疗消耗和并发症带来的医疗负担。' },
    @{ old = '已完成5例维持性血液透析合并活动性肺结核患者的预试验。所有患者均完成基线（T0）、治疗2个月（T2）、治疗6个月（T6）的IL-6及hs-CRP动态监测，并记录痰菌阴转、影像学吸收及不良事件：'; new = '已完成5例维持性血液透析合并活动性肺结核患者的先导性观察。所有患者均完成基线、治疗2个月及治疗6个月的IL-6和hs-CRP动态监测，并记录痰菌阴转、影像学变化及不良事件。' },
    @{ old = '10.2.1.基线IL-6中位数31.5 pg/mL，hs-CRP中位数45.7 mg/L，显著高于普通人群及单纯透析患者，证实共病状态下炎症负荷显著增加。'; new = '10.2.1 先导观察提示，共病患者基线IL-6和hs-CRP水平均处于较高水平，支持该人群存在较重炎症负荷。' },
    @{ old = '10.2.2.治疗2个月时，3例患者IL-6下降率≥35%（快速应答组），T2痰菌阴转率100%，治疗6个月均达到临床治愈；2例患者IL-6下降率<20%（缓慢应答组），T2痰菌均未阴转，其中1例发生药物性肝损伤后治疗失败，1例于治疗第4个月因心血管事件死亡。快速应答组与缓慢应答组在预后上呈现显著分离趋势。'; new = '10.2.2 部分患者在治疗2个月后炎症指标下降较明显，且治疗应答相对较好；另有部分患者炎症下降不明显，并出现治疗过程不良事件或结局不佳，提示动态变化可能与预后相关。由于样本量较小，上述结果仅用于支持研究可行性，不直接形成确认性阈值。' },
    @{ old = 'IL-6联合hs-CRP动态监测在MHD+TB患者中具有良好的可行性；治疗2个月IL-6下降率可作为早期预测治疗应答及预后的敏感指标。预试验结果为后续开展大样本正式研究提供了可靠的数据支持和可行性依据。'; new = 'IL-6联合hs-CRP动态监测在MHD+TB患者中具有一定可行性，值得在扩大样本的前瞻性研究中进一步验证其风险提示价值。' },
    @{ old = '课题负责人从事临床工作20余年，主持省级科研项目 5项，发表相关论文20余篇；核心成员包括临床医师4名（主任医师1名、主治医师3名）、检验技师2名（均为副主任技师）均从事结核病重点实验室检测工作10年以上，具备丰富的临床实践、实验室操作和数据分析经验。医院是以传染病（包括结核病）和肿瘤两大专科特色而建立的一所专科三级甲等医院，拥有病床930张，结核病 区118张。病床使用率均超过110%，是市结核病诊疗中心。病源覆盖全市及周边湖北、安徽等县市。我院结核科 在省学术界均具有一定社会影响，有能力支撑本课题的实施与完成。'; new = '课题组具备结核病临床诊疗、血液透析相关患者管理、样本处理和实验室检测基础。医院具有较稳定的病例来源和必要设备条件，可支持本研究的实施。正式开展前，课题组将进一步细化病例报告表、样本保存流程、数据管理分工和结局核查流程，以提高研究实施质量。' }
)

foreach ($pair in $pairs) {
    Replace-AllText -FindText $pair.old -ReplaceText $pair.new
}

